mapper.select:
SELECT T.CODE, T.PCODE, T.PLANT, T.TESTGUBUN, T.PROD_CD, T.LINE_CD, T.LOT_NO, T.AMPM, T.RESULT, T.WRITERID, CONVERT(VARCHAR(10), T.WDATE, 120) AS WDATE, S.PARTNO, G.PARTNM FROM TBL_PQC_TESTSCORE T LEFT JOIN TBL_INSP_STANDARD S ON T.PCODE = S.CODE LEFT JOIN TBL_COM_GOODS G ON S.PARTNO = G.PARTNO
T.SHOWYN = 'Y' AND T.PLANT = #{plant} AND T.TESTGUBUN = #{test_gubun} AND T.PROD_CD = #{prod_cd} AND (S.PARTNO LIKE #{part_no_nm} OR G.PARTNM LIKE #{part_no_nm}) AND T.LOT_NO LIKE #{lot_no} AND T.WDATE >= #{start_date} AND T.WDATE <= #{end_date}
ORDER BY T.WDATE DESC, T.CODE DESC
